ucs.kql:
// APT41 / BARIUM web-shell child-process recon
let _suspect_children = dynamic(["cmd.exe","powershell.exe","pwsh.exe","mshta.exe","rundll32.exe","regsvr32.exe","whoami.exe","net.exe","net1.exe","systeminfo.exe","ipconfig.exe","tasklist.exe","nltest.exe","wmic.exe","bitsadmin.exe","certutil.exe","quser.exe","hostname.exe","arp.exe","route.exe"]);
let _web_parents = dynamic(["w3wp.exe","httpd.exe","tomcat.exe","tomcat9.exe","java.exe","javaw.exe","jenkins.exe"]);
DeviceProcessEvents
| where Timestamp > ago(7d)
| where InitiatingProcessFileName in~ (_web_parents)
| where FileName in~ (_suspect_children)
// machine accounts excluded — IIS app-pool identities still keep these names
| where AccountName !in~ ("system")
| extend WebShellHostUser = InitiatingProcessAccountName
| project Timestamp, DeviceName, WebShellHostUser, InitiatingProcessFileName, InitiatingProcessFolderPath, InitiatingProcessCommandLine, ChildBinary = FileName, ChildCmd = ProcessCommandLine, SHA256, ReportId
| order by Timestamp desc
